mapper.select:
select s.id, s.biz, s.can_provide_invoice, s.compliance, s.create_at, s.nda_file_uri, b.avator as supplierAvatar, b.id as supplierBrandId, b.mark as supplierBrandMark, b.brand_name as supplierName, b.customer_id as supplierUserId, s.supplier_level, s.supplier_status, s.ux, b.modified_at as supplierLoginAt from supplier s inner join brand b on b.id = s.supplier_brand_id
s.purchaser_brand_id = #{purchaserBrandId}
AND s.supplier_status = #{dto.status}
AND (locate(#{dto.q}, s.biz)>0 or locate(#{dto.q}, b.brand_name)>0 or b.id=#{dto.q} or locate(#{dto.q}, b.handle)>0)
order by s.create_at desc
